import Header from '../components/layout/Header/Header';
import Footer from '../components/layout/Footer/Footer';
import ServiceCard from '../components/services/ServiceCard'; // <-- IMPORTANTE: Importamos o Card, não a Lista

// Importamos todos os dados de uma vez usando o "barril" (index.js)
import * as serviceData from '../data';

const Home = () => {
  return (
    <>
      <main>
        <section className="services-section">
          <div className="section-container">
            <ServiceList services={dataServices} />
            <ServiceList services={cleaningServices} />
            <ServiceList services={b2bServices} />
            <ServiceList services={performanceServices} />
            <ServiceList services={warrantyServices} />

          </div>
        </section>
      </main>
    </>
  );
};

export default Home;
